import{c as a,Q as r,j as e,m as i}from"./chunks/framework.BIBjCrbN.js";const c=JSON.parse('{"title":"医学物理 / 影像方向","description":"中国顶尖高校医学物理与医学影像方向博士导师汇总，涵盖MRI、超声成像、光学成像、放射物理等方向","frontmatter":{"title":"医学物理 / 影像方向","description":"中国顶尖高校医学物理与医学影像方向博士导师汇总，涵盖MRI、超声成像、光学成像、放射物理等方向"},"headers":[],"relativePath":"research-directions/medical-physics.md","filePath":"research-directions/medical-physics.md","lastUpdated":1780110618000}'),s={name:"research-directions/medical-physics.md"};function d(n,t,o,h,l,p){return r(),e("div",null,[...t[0]||(t[0]=[i('<h1 id="医学物理-影像" tabindex="-1">医学物理 / 影像 <a class="header-anchor" href="#医学物理-影像" aria-label="Permalink to &quot;医学物理 / 影像&quot;">​</a></h1><h2 id="方向概述" tabindex="-1">方向概述 <a class="header-anchor" href="#方向概述" aria-label="Permalink to &quot;方向概述&quot;">​</a></h2><p>医学物理运用物理学原理和方法解决医学成像、诊断和治疗中的问题。国内此方向在<strong>华中科技大学</strong>（超声/光学成像）、<strong>东南大学</strong>（生物电子学/纳米影像）、<strong>中山大学</strong>（医学影像）、<strong>清华大学</strong>（MRI/超声成像）有较强实力。</p><h2 id="子方向" tabindex="-1">子方向 <a class="header-anchor" href="#子方向" aria-label="Permalink to &quot;子方向&quot;">​</a></h2><ul><li><strong>磁共振成像 (MRI)</strong>：MRI物理、序列设计、重建算法 — 清华(郭华)</li><li><strong>超声成像与治疗</strong>：弹性成像、HIFU治疗 — 清华(罗建文)</li><li><strong>光学成像</strong>：双光子/共聚焦/近红外 — 华科(武汉光电国家研究中心)</li><li><strong>医学图像处理与分析</strong>：AI辅助诊断 — 清华(张洋)</li><li><strong>放射治疗物理</strong>：剂量计算、治疗计划 — 中山大学</li><li><strong>分子影像</strong>：PET/SPECT/MRI多模态 — 华科</li></ul><hr><h2 id="导师全索引" tabindex="-1">导师全索引 <a class="header-anchor" href="#导师全索引" aria-label="Permalink to &quot;导师全索引&quot;">​</a></h2><h3 id="清华大学" tabindex="-1">清华大学 <a class="header-anchor" href="#清华大学" aria-label="Permalink to &quot;清华大学&quot;">​</a></h3><table tabindex="0"><thead><tr><th>导师</th><th>职称</th><th>所在学院</th><th>核心方向</th></tr></thead><tbody><tr><td><a href="/apply-phd/universities/tsinghua#——-生物医学成像与图像处理方向——">郭华</a></td><td>教授</td><td>生物医学工程学院</td><td>医学影像、MRI物理与工程</td></tr><tr><td><a href="/apply-phd/universities/tsinghua#——-生物医学成像与图像处理方向——">罗建文</a></td><td>教授</td><td>生物医学工程学院</td><td>超声成像、弹性成像</td></tr><tr><td><a href="/apply-phd/universities/tsinghua#——-生物医学成像与图像处理方向——">陈慧军</a></td><td>教授</td><td>生物医学工程学院</td><td>医学影像处理与分析</td></tr><tr><td><a href="/apply-phd/universities/tsinghua#——-生物医学成像与图像处理方向——">廖洪恩</a></td><td>教授</td><td>生物医学工程学院</td><td>医学影像引导治疗、微创诊疗</td></tr><tr><td><a href="/apply-phd/universities/tsinghua#——-生物医学成像与图像处理方向——">田启源</a></td><td>教授</td><td>生物医学工程学院</td><td>计算影像、光学成像</td></tr><tr><td><a href="/apply-phd/universities/tsinghua#——-生物医学成像与图像处理方向——">张洋</a></td><td>教授</td><td>生物医学工程学院</td><td>医学图像处理、AI辅助诊断</td></tr></tbody></table><p>详见 <a href="/apply-phd/universities/tsinghua">清华大学</a> 页面。</p><h3 id="华中科技大学" tabindex="-1">华中科技大学 <a class="header-anchor" href="#华中科技大学" aria-label="Permalink to &quot;华中科技大学&quot;">​</a></h3><p>武汉光电国家研究中心在<strong>生物医学光子学</strong>和<strong>光学成像</strong>方向有顶尖平台。 详见 <a href="/apply-phd/universities/hust">华中科技大学</a> 页面。</p><h3 id="东南大学" tabindex="-1">东南大学 <a class="header-anchor" href="#东南大学" aria-label="Permalink to &quot;东南大学&quot;">​</a></h3><p>生物科学与医学工程学院在生物电子学、纳米影像方向有特色。 详见 <a href="/apply-phd/universities/seu">东南大学</a> 页面。</p><h3 id="中山大学" tabindex="-1">中山大学 <a class="header-anchor" href="#中山大学" aria-label="Permalink to &quot;中山大学&quot;">​</a></h3><p>生物医学工程学院（深圳校区）在医学影像方向有布局。 详见 <a href="/apply-phd/universities/sysu">中山大学</a> 页面。</p><h3 id="中国科学技术大学" tabindex="-1">中国科学技术大学 <a class="header-anchor" href="#中国科学技术大学" aria-label="Permalink to &quot;中国科学技术大学&quot;">​</a></h3><p>物理/工程学科基础雄厚，医学物理方向可考虑。 详见 <a href="/apply-phd/universities/ustc">中国科学技术大学</a> 页面。</p><hr><h2 id="针对你的申请建议" tabindex="-1">针对你的申请建议 <a class="header-anchor" href="#针对你的申请建议" aria-label="Permalink to &quot;针对你的申请建议&quot;">​</a></h2><p>医学物理方向与你的背景匹配度分析：</p><ul><li><strong>光学成像</strong>：⭐⭐⭐⭐ — 硕士期间使用双光子/共聚焦显微镜，有实际经验</li><li><strong>超声成像/治疗</strong>：⭐⭐⭐⭐ — UCL暑期RA经验（HIFU系统评估+校准），本科医学物理背景</li><li><strong>MRI</strong>：⭐⭐⭐ — 本科物理基础好，但可能缺乏专门MRI研究经验</li><li><strong>医学图像处理 (AI)</strong>：⭐⭐⭐ — Python/MATLAB编程能力强，但需展示相关项目</li></ul><p>建议策略：</p><ul><li><strong>超声方向</strong>最有说服力：UCL医用物理本科 + HIFU系统暑期RA经验 = 完整的叙事线</li><li><strong>光学成像</strong>与硕士钙成像经验衔接：双光子显微镜操作+温度控制系统开发</li><li>申请时可强调<strong>医学物理本科的物理/数学基础</strong>（很多BME申请人缺乏）和<strong>实际设备操作经验</strong></li></ul>',24)])])}const g=a(s,[["render",d]]);export{c as __pageData,g as default};
